package com.example.yourappname; // IMPORTANT: Replace with your actual package name

import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.net.Uri;
import android.os.Bundle;
import android.util.Log;
import android.view.View;
import android.webkit.MimeTypeMap;
import android.widget.ImageView;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;
import java.io.InputStream;

public class DocumentViewerActivity extends AppCompatActivity {

    private static final String TAG = "DocumentViewerActivity";
    private TextView documentUriTextView;
    private TextView documentMimeTypeTextView;
    private ImageView documentImageView;
    private TextView documentPlaceholderTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_document_viewer);

        documentUriTextView = findViewById(R.id.documentUriTextView);
        documentMimeTypeTextView = findViewById(R.id.documentMimeTypeTextView);
        documentImageView = findViewById(R.id.documentImageView);
        documentPlaceholderTextView = findViewById(R.id.documentPlaceholderTextView);

        // Since launchMode is "standard", onCreate will be called for every new intent.
        handleIntent(getIntent());
    }

    private void handleIntent(Intent intent) {
        if (Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri documentUri = intent.getData();
            if (documentUri != null) {
                Log.d(TAG, "Received VIEW intent for URI: " + documentUri);
                documentUriTextView.setText("URI: " + documentUri.toString());

                String mimeType = getContentResolver().getType(documentUri);
                if (mimeType == null) {
                    // Fallback: Try to infer MIME type from file extension
                    String extension = MimeTypeMap.getFileExtensionFromUrl(documentUri.toString());
                    if (extension != null) {
                        mimeType = MimeTypeMap.getSingleton().getMimeTypeFromExtension(extension);
                    }
                }
                documentMimeTypeTextView.setText("Mime Type: " + (mimeType != null ? mimeType : "Unknown"));
                Log.d(TAG, "Inferred Mime Type: " + mimeType);

                if (mimeType != null && mimeType.startsWith("image/")) {
                    displayImage(documentUri);
                } else if (mimeType != null && mimeType.equals("application/pdf")) {
                    // For PDFs, we'll show a placeholder as a full PDF renderer is complex
                    displayPlaceholderForPdf();
                }
                else {
                    displayPlaceholderForOtherDocs();
                }
            } else {
                documentUriTextView.setText("No URI found in intent.");
                documentMimeTypeTextView.setText("Mime Type: N/A");
                Log.e(TAG, "Received VIEW intent with null data URI.");
            }
        } else {
            documentUriTextView.setText("Activity launched without a VIEW action.");
            documentMimeTypeTextView.setText("Mime Type: N/A");
            Log.d(TAG, "Activity launched with action: " + intent.getAction());
        }
    }

    private void displayImage(Uri imageUri) {
        try {
            // Use ContentResolver to open an InputStream for the URI
            InputStream inputStream = getContentResolver().openInputStream(imageUri);
            if (inputStream != null) {
                Bitmap bitmap = BitmapFactory.decodeStream(inputStream);
                if (bitmap != null) {
                    documentImageView.setImageBitmap(bitmap);
                    documentImageView.setVisibility(View.VISIBLE);
                    documentPlaceholderTextView.setVisibility(View.GONE);
                    Log.d(TAG, "Image displayed successfully.");
                } else {
                    Log.e(TAG, "Failed to decode image from stream.");
                    displayErrorPlaceholder("Failed to load image.");
                }
                inputStream.close();
            } else {
                Log.e(TAG, "Could not open input stream for image URI.");
                displayErrorPlaceholder("Could not open image.");
            }
        } catch (Exception e) {
            Log.e(TAG, "Error displaying image: " + e.getMessage(), e);
            displayErrorPlaceholder("Error displaying image: " + e.getLocalizedMessage());
        }
    }

    private void displayPlaceholderForPdf() {
        documentImageView.setVisibility(View.GONE);
        documentPlaceholderTextView.setText("This app supports PDF files, but direct viewing functionality is not integrated into this basic example. The file URI is shown above.");
        documentPlaceholderTextView.setVisibility(View.VISIBLE);
        Log.d(TAG, "Displaying placeholder for PDF document.");
    }

    private void displayPlaceholderForOtherDocs() {
        documentImageView.setVisibility(View.GONE);
        documentPlaceholderTextView.setText("This app can open PDFs and images. For other document types, the URI is shown above.");
        documentPlaceholderTextView.setVisibility(View.VISIBLE);
        Log.d(TAG, "Displaying placeholder for non-image/non-pdf document.");
    }

    private void displayErrorPlaceholder(String message) {
        documentImageView.setVisibility(View.GONE);
        documentPlaceholderTextView.setText(message + "\nURI shown above.");
        documentPlaceholderTextView.setVisibility(View.VISIBLE);
    }
}